//! neurosymbolic-tool-markov — scores a System 2 tool walk as a finite
//! Markov witness over synthetic-gnosis gain and residual shadow.
//!
//! Usage:
//!   neurosymbolic-tool-markov --json-file tool-walk.json --print-json
//!   neurosymbolic-tool-markov --json <B64_JSON> --output-frame tool-walk.frame
//!   neurosymbolic-tool-markov --json-file tool-walk.json --print-frame-base64

use base64::{engine::general_purpose::STANDARD as BASE64_STANDARD, Engine as _};
use distributed_inference::neurosymbolic_tool_markov::{
    compile_neurosymbolic_tool_markov_report, tool_markov_report_to_frame, ToolUseMarkovSpec,
};
use std::env;
use std::fs;
use std::io::{self, Write};
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = env::args().collect();
    let options = CliOptions::parse(&args)?;
    let spec_json = options.read_spec_json()?;
    let spec: ToolUseMarkovSpec = serde_json::from_slice(&spec_json)?;
    let report = compile_neurosymbolic_tool_markov_report(spec);

    if let Some(output_report_path) = &options.output_report_path {
        fs::write(
            Path::new(output_report_path),
            serde_json::to_vec_pretty(&report)?,
        )?;
    }

    let mut emitted = false;
    if let Some(output_frame_path) = &options.output_frame_path {
        let frame = tool_markov_report_to_frame(&report)?;
        fs::write(Path::new(output_frame_path), bincode::serialize(&frame)?)?;
        emitted = true;
    }

    if options.print_frame_base64 {
        let frame = tool_markov_report_to_frame(&report)?;
        println!("{}", BASE64_STANDARD.encode(bincode::serialize(&frame)?));
        emitted = true;
    }

    if options.print_json || !emitted {
        let mut stdout = io::stdout();
        stdout.write_all(&serde_json::to_vec_pretty(&report)?)?;
        stdout.write_all(b"\n")?;
        stdout.flush()?;
    }

    Ok(())
}

#[derive(Debug)]
struct CliOptions {
    json_b64: Option<String>,
    json_file: Option<String>,
    output_report_path: Option<String>,
    output_frame_path: Option<String>,
    print_json: bool,
    print_frame_base64: bool,
}

impl CliOptions {
    fn parse(args: &[String]) -> io::Result<Self> {
        let mut json_b64 = None;
        let mut json_file = None;
        let mut output_report_path = None;
        let mut output_frame_path = None;
        let mut print_json = false;
        let mut print_frame_base64 = false;

        let mut index = 1;
        while index < args.len() {
            match args[index].as_str() {
                "--json" => {
                    index += 1;
                    json_b64 = Some(required_value(args, index, "--json <BASE64_JSON>")?);
                }
                "--json-file" => {
                    index += 1;
                    json_file = Some(required_value(args, index, "--json-file <PATH>")?);
                }
                "--output-report" => {
                    index += 1;
                    output_report_path =
                        Some(required_value(args, index, "--output-report <PATH>")?);
                }
                "--output-frame" => {
                    index += 1;
                    output_frame_path = Some(required_value(args, index, "--output-frame <PATH>")?);
                }
                "--print-json" => {
                    print_json = true;
                }
                "--print-frame-base64" => {
                    print_frame_base64 = true;
                }
                "--help" | "-h" => {
                    return Err(io::Error::new(io::ErrorKind::InvalidInput, usage()));
                }
                other => {
                    return Err(io::Error::new(
                        io::ErrorKind::InvalidInput,
                        format!("unknown argument: {other}\n{}", usage()),
                    ));
                }
            }
            index += 1;
        }

        if usize::from(json_b64.is_some()) + usize::from(json_file.is_some()) != 1 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                format!(
                    "provide exactly one of --json <BASE64_JSON> or --json-file <PATH>\n{}",
                    usage()
                ),
            ));
        }

        Ok(Self {
            json_b64,
            json_file,
            output_report_path,
            output_frame_path,
            print_json,
            print_frame_base64,
        })
    }

    fn read_spec_json(&self) -> Result<Vec<u8>, Box<dyn std::error::Error>> {
        if let Some(b64) = &self.json_b64 {
            return Ok(BASE64_STANDARD.decode(b64)?);
        }
        let path = self.json_file.as_ref().ok_or_else(|| {
            io::Error::new(io::ErrorKind::InvalidInput, "missing --json or --json-file")
        })?;
        Ok(fs::read(path)?)
    }
}

fn required_value(args: &[String], index: usize, flag: &str) -> io::Result<String> {
    args.get(index).cloned().ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidInput,
            format!("missing value for {flag}"),
        )
    })
}

fn usage() -> String {
    "usage: neurosymbolic-tool-markov (--json <BASE64_JSON> | --json-file <PATH>) [--output-report <PATH>] [--output-frame <PATH>] [--print-json] [--print-frame-base64]".to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_requires_one_input() {
        let args = vec!["neurosymbolic-tool-markov".to_string()];
        let error = CliOptions::parse(&args).expect_err("missing input");
        assert!(error.to_string().contains("provide exactly one"));
    }

    #[test]
    fn parse_accepts_json_file_and_frame_output() {
        let args = vec![
            "neurosymbolic-tool-markov".to_string(),
            "--json-file".to_string(),
            "walk.json".to_string(),
            "--output-frame".to_string(),
            "walk.frame".to_string(),
            "--print-json".to_string(),
        ];
        let options = CliOptions::parse(&args).expect("options");
        assert_eq!(options.json_file.as_deref(), Some("walk.json"));
        assert_eq!(options.output_frame_path.as_deref(), Some("walk.frame"));
        assert!(options.print_json);
    }
}
